const maxRetries = 3;
let attempt = 0;

while (attempt < maxRetries) {
  try {
    const result = executeTool(toolName, toolInput);
    const toolResult = {
      type: "tool_result",
      tool_use_id: toolId,
      content: JSON.stringify(result),
      is_error: false
    };
    break; // Success, exit retry loop
  } catch (error) {
    attempt++;
    if (attempt === maxRetries) {
      const toolResult = {
        type: "tool_result",
        tool_use_id: toolId,
        content: `Failed after ${maxRetries} attempts: ${error.message}`,
        is_error: true
      };
    } else {
      // Log and retry
      console.warn(`Attempt ${attempt} failed: ${error.message}. Retrying...`);
    }
  }
}

